<!-- /wp:paragraph -->

<!-- wp:paragraph -->
<p><strong>Adresse :</strong><br>388, rue Main, Ottawa (Ontario), Canada, K1S 1E3</p>
<!-- /wp:paragraph -->

<!-- wp:paragraph -->
<p><strong>Téléphone</strong> <strong>:</strong>&nbsp;<a href="tel:613-563-0141">613-563-0141</a></p>
